import{_ as e,o as l,c as d,ag as a}from"./chunks/framework.DTiDeF2Q.js";const x=JSON.parse('{"title":"Default 别名 | Dotfiles (ZH)","titleTemplate":":title","description":"基本 shell 别名，用于导航、系统控制和日常任务。使用这些通用快捷方式简化终端工作流。","frontmatter":{"title":"Default 别名 | Dotfiles","description":"基本 shell 别名，用于导航、系统控制和日常任务。使用这些通用快捷方式简化终端工作流。","lang":"zh-CN","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Default 别名 preview","canonical":"/zh/aliases/default/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Default 别名","pageType":"docs","schemaType":"WebPage","metaTitle":"Default 别名 - Dotfiles (CN)","permalink":"/zh/aliases/default/","sidebar":true,"meta":[{"name":"keywords","content":"默认别名, shell 别名, 终端快捷方式, dotfiles, bash 别名"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Default 别名 - Dotfiles"},{"name":"twitter:description","content":"基本 shell 别名，用于导航、系统控制和日常任务。"},{"name":"og:title","content":"Default 别名 - Dotfiles"},{"name":"og:description","content":"基本 shell 别名，用于导航、系统控制和日常任务。"},{"name":"og:image:alt","content":"Dotfiles - 为你的 Shell 生活精心设计"},{"name":"og:locale","content":"zh_CN"}]},"headers":[],"relativePath":"zh/aliases/default/index.md","filePath":"zh/aliases/default/index.md","lastUpdated":1773010926000}'),o={name:"zh/aliases/default/index.md"};function i(n,t,s,c,r,f){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="default-别名" tabindex="-1">Default 别名 <a class="header-anchor" href="#default-别名" aria-label="Permalink to &quot;Default 别名&quot;">​</a></h1><p>日常终端任务的基本 shell 快捷方式。</p><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>默认别名提供了一系列通用 shell 快捷方式，简化常见的终端操作。这些别名定义在 <code>default.aliases.sh</code> 中，由 chezmoi 在所有支持的 shell 中自动加载。</p><p>这些快捷方式涵盖通用工具、退出命令、网络诊断、系统监控和文件系统导航。</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><h3 id="通用" tabindex="-1">通用 <a class="header-anchor" href="#通用" aria-label="Permalink to &quot;通用&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">命令</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>da</code></td><td style="text-align:left;"><code>date &quot;+%Y-%m-%d %A %T %Z&quot;</code></td><td style="text-align:left;">显示当前日期和时间</td></tr><tr><td style="text-align:left;"><code>p</code></td><td style="text-align:left;"><code>pwd</code></td><td style="text-align:left;">打印工作目录</td></tr><tr><td style="text-align:left;"><code>path</code></td><td style="text-align:left;"><code>echo ${PATH//:/\\\\n}</code></td><td style="text-align:left;">逐行显示 PATH 变量</td></tr><tr><td style="text-align:left;"><code>r</code></td><td style="text-align:left;"><code>reload</code></td><td style="text-align:left;">重新加载 shell</td></tr><tr><td style="text-align:left;"><code>t</code></td><td style="text-align:left;"><code>tail -f</code></td><td style="text-align:left;">实时跟踪文件输出</td></tr><tr><td style="text-align:left;"><code>wk</code></td><td style="text-align:left;"><code>date +%V</code></td><td style="text-align:left;">显示当前周数</td></tr></tbody></table><h3 id="退出和关机" tabindex="-1">退出和关机 <a class="header-anchor" href="#退出和关机" aria-label="Permalink to &quot;退出和关机&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">命令</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>q</code></td><td style="text-align:left;"><code>exit</code></td><td style="text-align:left;">退出 shell</td></tr><tr><td style="text-align:left;"><code>quit</code></td><td style="text-align:left;"><code>exit</code></td><td style="text-align:left;">退出 shell</td></tr><tr><td style="text-align:left;"><code>bye</code></td><td style="text-align:left;"><code>exit</code></td><td style="text-align:left;">退出 shell</td></tr><tr><td style="text-align:left;"><code>:q</code></td><td style="text-align:left;"><code>exit</code></td><td style="text-align:left;">退出 shell（vim 风格）</td></tr><tr><td style="text-align:left;"><code>halt</code></td><td style="text-align:left;"><code>sudo /sbin/halt</code></td><td style="text-align:left;">停止系统</td></tr><tr><td style="text-align:left;"><code>poweroff</code></td><td style="text-align:left;"><code>sudo /sbin/shutdown</code></td><td style="text-align:left;">关闭系统</td></tr><tr><td style="text-align:left;"><code>reboot</code></td><td style="text-align:left;"><code>sudo /sbin/reboot</code></td><td style="text-align:left;">重启系统</td></tr></tbody></table><h3 id="历史" tabindex="-1">历史 <a class="header-anchor" href="#历史" aria-label="Permalink to &quot;历史&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">命令</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>h</code></td><td style="text-align:left;"><code>history</code></td><td style="text-align:left;">查看命令历史</td></tr><tr><td style="text-align:left;"><code>history</code></td><td style="text-align:left;"><code>fc -il 1</code></td><td style="text-align:left;">显示带 ISO 8601 时间戳的历史</td></tr></tbody></table><h3 id="网络" tabindex="-1">网络 <a class="header-anchor" href="#网络" aria-label="Permalink to &quot;网络&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">命令</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>ifconfig</code></td><td style="text-align:left;"><code>sudo ifconfig</code></td><td style="text-align:left;">配置网络接口</td></tr><tr><td style="text-align:left;"><code>ipinfo</code></td><td style="text-align:left;"><code>ipconfig getpacket en0</code></td><td style="text-align:left;">获取 en0 的网络参数</td></tr><tr><td style="text-align:left;"><code>nls</code></td><td style="text-align:left;"><code>sudo lsof -i -P | grep LISTEN</code></td><td style="text-align:left;">显示活动的网络监听器</td></tr><tr><td style="text-align:left;"><code>op</code></td><td style="text-align:left;"><code>sudo lsof -i -P</code></td><td style="text-align:left;">列出开放端口</td></tr><tr><td style="text-align:left;"><code>ping</code></td><td style="text-align:left;"><code>ping -c 5</code></td><td style="text-align:left;">限制 5 个数据包的 ping</td></tr><tr><td style="text-align:left;"><code>ports</code></td><td style="text-align:left;"><code>netstat -tulan</code></td><td style="text-align:left;">列出所有监听端口</td></tr></tbody></table><h3 id="系统监控" tabindex="-1">系统监控 <a class="header-anchor" href="#系统监控" aria-label="Permalink to &quot;系统监控&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">命令</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>top</code></td><td style="text-align:left;"><code>sudo btop</code></td><td style="text-align:left;">交互式进程监控器</td></tr><tr><td style="text-align:left;"><code>spd</code></td><td style="text-align:left;"><code>sudo rm -rf /private/var/log/asl/*</code></td><td style="text-align:left;">清除 ASL 日志文件</td></tr></tbody></table><h3 id="工具" tabindex="-1">工具 <a class="header-anchor" href="#工具" aria-label="Permalink to &quot;工具&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">别名</th><th style="text-align:left;">命令</th><th style="text-align:left;">描述</th></tr></thead><tbody><tr><td style="text-align:left;"><code>ctf</code></td><td style="text-align:left;"><code>ls -1 | wc -l</code></td><td style="text-align:left;">计算当前目录中的文件数</td></tr><tr><td style="text-align:left;"><code>qfind</code></td><td style="text-align:left;"><code>find . -name</code></td><td style="text-align:left;">快速文件搜索</td></tr><tr><td style="text-align:left;"><code>reload</code></td><td style="text-align:left;"><code>exec $SHELL -l</code></td><td style="text-align:left;">重新加载 shell</td></tr><tr><td style="text-align:left;"><code>wth</code></td><td style="text-align:left;"><code>curl -s &quot;wttr.in/?format=3&quot;</code></td><td style="text-align:left;">获取当前天气</td></tr></tbody></table>',18)])])}const g=e(o,[["render",i]]);export{x as __pageData,g as default};
